import React, { useState, useCallback, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { validarEmail, validarPassword } from "../utils/validations";
import Button from "../components/Shared/Button";
import Input from "../components/Shared/Input";

export default function Login() {
  const navigate          = useNavigate();
  const { login, isAuthenticated } = useAuth();

  const [email, setEmail]       = useState("");
  const [password, setPass]     = useState("");
  const [emailErr, setEmailErr] = useState("");
  const [passErr, setPassErr]   = useState("");
  const [apiErr, setApiErr]     = useState("");
  const [loading, setLoading]   = useState(false);
  const [touched, setTouched]   = useState({ email: false, pass: false });

  /* Si ya está autenticado, ir al dashboard */
  useEffect(() => {
    if (isAuthenticated) navigate("/dashboard", { replace: true });
  }, [isAuthenticated, navigate]);

  /* Validar en tiempo real solo si ya tocó el campo */
  useEffect(() => {
    if (touched.email) setEmailErr(validarEmail(email) || "");
  }, [email, touched.email]);

  useEffect(() => {
    if (touched.pass) setPassErr(validarPassword(password) || "");
  }, [password, touched.pass]);

  const canSubmit = !emailErr && !passErr && email && password;

  const handleSubmit = useCallback(async (e) => {
    e.preventDefault();
    setTouched({ email: true, pass: true });

    const eErr = validarEmail(email);
    const pErr = validarPassword(password);
    setEmailErr(eErr || "");
    setPassErr(pErr || "");
    if (eErr || pErr) return;

    setLoading(true);
    setApiErr("");

    const result = await login(email, password);
    setLoading(false);

    if (result.success) {
      navigate("/dashboard", { replace: true });
    } else {
      setApiErr(result.error);
    }
  }, [email, password, login, navigate]);

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-primary-50 via-white to-teal-50 px-4">
      <div className="w-full max-w-md animate-fade-in">

        {/* Logo / branding */}
        <div className="text-center mb-8">
          <div className="inline-flex w-16 h-16 rounded-2xl bg-brand-teal items-center justify-center mb-4 shadow-lg">
            <span className="text-white font-bold text-2xl select-none">SC</span>
          </div>
          <h1 className="text-2xl font-bold text-gray-800">SICOPS</h1>
          <p className="text-gray-500 text-sm mt-1">Sistema de Control de Obras y Porcentajes</p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-2xl shadow-xl border border-gray-100 px-8 py-8">
          <h2 className="text-lg font-semibold text-gray-700 mb-6">Iniciar sesión</h2>

          <form onSubmit={handleSubmit} noValidate className="space-y-4">
            <Input
              label="Correo electrónico"
              type="email"
              id="login-email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              error={emailErr}
              placeholder="admin@obra.com"
              required
              autoComplete="email"
              autoFocus
            />

            <Input
              label="Contraseña"
              type="password"
              id="login-pass"
              value={password}
              onChange={(e) => setPass(e.target.value)}
              onBlur={() => setTouched((t) => ({ ...t, pass: true }))}
              error={passErr}
              placeholder="••••••••"
              required
              autoComplete="current-password"
            />

            {/* Error API */}
            {apiErr && (
              <div role="alert" className="flex items-center gap-2 px-4 py-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-700 animate-shake">
                <span>⚠️</span>
                {apiErr}
              </div>
            )}

            <Button
              type="submit"
              size="lg"
              disabled={!canSubmit}
              loading={loading}
              className="w-full mt-2"
              aria-label="Iniciar sesión en SICOPS"
            >
              Iniciar sesión
            </Button>
          </form>

          {/* Hint mock */}
          <div className="mt-6 p-3 bg-gray-50 rounded-lg border border-dashed border-gray-200">
            <p className="text-xs text-gray-400 font-medium mb-1">Credenciales de prueba:</p>
            <p className="text-xs font-mono text-gray-600">admin@obra.com</p>
            <p className="text-xs font-mono text-gray-600">123456</p>
          </div>
        </div>

        <p className="text-center text-xs text-gray-400 mt-6">
          © {new Date().getFullYear()} SICOPS · Modo Mock
        </p>
      </div>
    </div>
  );
}
